# CONVERSION FUNCTIONS
# =============================================================================


def _mc_monitor_to_nested(mc_monitor: MCMonitor) -> MCMonitorNested:
    """Convert flat MCMonitor to nested format."""
    attrs = MCMonitorAttributes()
    _populate_mc_monitor_attrs(attrs, mc_monitor)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        mc_monitor, _MC_MONITOR_REL_FIELDS, MCMonitorRelationshipAttributes
    )
    return MCMonitorNested(
        guid=mc_monitor.guid,
        type_name=mc_monitor.type_name,
        status=mc_monitor.status,
        version=mc_monitor.version,
        create_time=mc_monitor.create_time,
        update_time=mc_monitor.update_time,
        created_by=mc_monitor.created_by,
        updated_by=mc_monitor.updated_by,
        classifications=mc_monitor.classifications,
        classification_names=mc_monitor.classification_names,
        meanings=mc_monitor.meanings,
        labels=mc_monitor.labels,
        business_attributes=mc_monitor.business_attributes,
        custom_attributes=mc_monitor.custom_attributes,
        pending_tasks=mc_monitor.pending_tasks,
        proxy=mc_monitor.proxy,
        is_incomplete=mc_monitor.is_incomplete,
        provenance_type=mc_monitor.provenance_type,
        home_id=mc_monitor.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _mc_monitor_from_nested(nested: MCMonitorNested) -> MCMonitor:
    """Convert nested format to flat MCMonitor."""
    attrs = nested.attributes if nested.attributes is not UNSET else MCMonitorAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MC_MONITOR_REL_FIELDS,
        MCMonitorRelationshipAttributes
    )
    return MCMonitor(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_mc_monitor_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _mc_monitor_to_nested_bytes(mc_monitor: MCMonitor, serde: Serde) -> bytes:
    """Convert flat MCMonitor to nested JSON bytes."""
    return serde.encode(_mc_monitor_to_nested(mc_monitor))


def _mc_monitor_from_nested_bytes(data: bytes, serde: Serde) -> MCMonitor:
    """Convert nested JSON bytes to flat MCMonitor."""
    nested = serde.decode(data, MCMonitorNested)
    return _mc_monitor_from_nested(nested)

